-- ============================================================
-- IMAGO — locales/base/data/snippets.lua (enUS fallback)
-- ============================================================

IMAGO.LoreSnippets["FUN_FACT"] = {
    { text = "Spirit Healers are actually rogue Val'kyr." },
    { text = "Nat Pagle once said: 'You can't catch 'em all if you don't cast a line.'" },
    { text = "IMAGO - The Chronicle of the Unforgotten is never finished - only expanded." },
    { text = "Murlocs speak Nerglish." },
    { text = "The Defias Brotherhood was right." },
    { text = "Bolvar Fordragon was the Lich King longer than Arthas Menethil." },
    { text = "The whispers in the Lordaeron throne room are the last conversation between Arthas and his father from Warcraft III. Turn up your ambient volume to hear them for yourself!" },
    { text = "Critters such as seals and boars have been known to explode when repeatedly poked. This phenomenon has mysteriously stopped since the end of the Third War." },
    { text = "Illidan Stormrage wields the Twinblades of Azzinoth. In their original depiction, they had panda faces engraved at the grip." },
    { text = "Many prominent characters are known to smoke tobacco, including King Terenas, Khadgar, Uther the Lightbringer, and Tirion Fordring." },
    { text = "Stratholme has a sign that points which way to go to reach Stranglethorn, despite that region being on the opposite side of the continent." },
    { text = "Dreadsteeds are raised by the stablemaster demon lord Hel'nurath on the planet Xoroth. To his dismay, warlocks keep stealing them in their summoning rituals." },
    { text = "Alleria and Turalyon aren't married despite having been together for over a thousand years." },
    { text = "Goblin Shredders have a picture of Kerrigan from StarCraft: Brood War on their main screen." },
    { text = "Thrall has blue eyes, which is an extremely rare trait among orcs." },
    { text = "Lordaeron is named after Lordain, a human general who played a pivotal role in the Troll Wars nearly 3,000 years ago." },
    { text = "Ogres regularly hold arm wrestling championships. Guard Mol'dar has been the Dire Maul arm wrestling champion for six years running." },
    { text = "Trolls tend to name their cities after their tribe. The Gurubashi built Zul'Gurub, the Amani live in Zul'Aman, the Farraki shelter in Zul'Farrak, and the Drakkari has Zul'Drak." },
    { text = "When it comes to alcoholic drinks, Tirion Fordring recommends Hearthglen Ambrosia." },
    { text = "The Kirin Tor has a compendium of rules and regulations on the use of the polymorph spell. It is hundreds of pages long." },
    { text = "Dragons believe that mortal races use large, ornate shoulder armor to emulate the majestic wings of dragons." },
    { text = "Most clocks in Azeroth are broken, with arms locked in place. They don't accurately tell the time." },
    { text = "The gnome Tigule invented ice cream, and became incredibly rich selling his flagship strawberry flavor." },
    { text = "Stranglekelp was used to make ice cream during the Ahn'Qiraj war effort to help soldiers mitigate the desert heat." },
    { text = "The Forsaken adopted Gutterspeak to prevent other races from listening in on their schemes. It's a modified form of Common that uses bits of Dwarven and Thalassian." },
    { text = "The warlock spell \"Eye of Kilrogg\" is named after Kilrogg Deadeye, former orc chieftain of the Bleeding Hollow clan." },
    { text = "The Dark Portal features two humanoid statues at each side. No one knows who they're supposed to depict." },
    { text = "\"Tauren\" is an anagram for \"nature\"." },
    { text = "The Wailing Caverns got its name from the sound of water rushing through fissures in the ground that sound like eerie, haunting cries." },
    { text = "The ship found in the Deadmines is an Ogre Juggernaught, a common sight during the Second War." },
    { text = "Creatures under the effects of Curse of Tongues are forced to speak in Demonic." },
    { text = "Binary Brew, obtained from the Brew of the Month Club, temporarily grants the ability to speak in binary." },
    { text = "The orcish phrase \"Zug-zug\" means acknowledgement or agreement." },
    { text = "Enemies appear to be lower level while you're drunk." },
    { text = "Forsaken can be healed with the Light, though it comes with intense pain." },
    { text = "Orgrimmar was named after Orgrim Doomhammer, second Warchief of the Horde." },
    { text = "Durotar was named after Thrall's father, Durotan of the Frostwolf Clan." },
    { text = "Saronite, a metal found in Northrend, is the condensed blood of the Old God Yogg-Saron. Prolonged exposure induces madness." },
    { text = "September 30th is Peon Day, where the people of Stormwind and Orgrimmar celebrate the diligent work of the humble peons and peasants of the world." },
    { text = "Despite the fact that he wears plate armor and wields a sword, Anduin Wrynn is considered a priest, not a paladin." },
    { text = "Booty Bay was originally called Blackwater Cove." },
    { text = "Adventurers had to burn a permanent draconic mark on their skin to attune to Blackwing Lair. This branded mark has never been made visible on player models." },
    { text = "Ancient tauren shamans once mistook the earth elemental Princess Therazane as the Earth Mother." },
    { text = "After he was turned to diamond at Old Ironforge, Magni Bronzebeard became too heavy to ride the lifts at Thunder Bluff." },
    { text = "Chen Stormstout calls the Darkspear trolls living in Thunder Bluff \"Blue Tauren\"." },
    { text = "Finely-ground draenei tail is a potent ingredient for necromantic experiments." },
    { text = "Void elves find the chiming noises made by Naaru very irritating." },
}

IMAGO.LoreSnippets["DID_YOU_KNOW"] = {
    { text = "Azeroth can refer to five different things: Azeroth the Titan, Azeroth the planet, Azeroth the continent (Eastern Kingdoms), Azeroth the region (south of Khaz Modan), and Azeroth the kingdom (now called the Kingdom of Stormwind)." },
    { text = "Goblins are a failed experiment by Titan Keeper Mimiron." },
    { text = "Duskwood used to be known as Brightwood until the Guardian Medivh's death. The Guardian's death caused a wave of fel energy that caused an everlasting night." },
    { text = "Elves are magically evolved trolls." },
    { text = "The Void is not empty, but instead an amalgamation of energy akin to the burning insides of a star. Many have been driven mad by it." },
    { text = "The Wretched are blood elves that succumbed to their addiction to magic, becoming feral and deformed as a result." },
    { text = "Ogres are surprisingly good shipwrights and sailors." },
    { text = "Tartek the Enraged was one of the most powerful Abominations to ever be created. We only know of his existence through a single piece of Scourge literature in the Ebon Hold." },
    { text = "The Wildhammer dwarves are famous for riding gryphons and wielding Stormhammers—enchanted weapons that strike with the force of thunder and lightning when thrown." },
    { text = "The Discs of Norgannon, sometimes referred to as the Platinum Discs, are a wondrous artifact entombed in Uldaman. They are a library of Azeroth's entire history, and new information continues to be recorded within them as they occur." },
    { text = "Obsidian may have the capacity to manipulate mana, as evidenced by the Obsidian Sentinel in Uldaman and the Obsidian Destroyers employed by the Scourge and the Qiraji." },
    { text = "While the forces of the Scarlet Monastery are primarily human, the Scarlet Armory features three statues honoring non-human members of the Scarlet Crusade." },
    { text = "In extremely rare cases, instead of resurrection, the Holy Light will produce an undead animated with Light instead of necromancy." },
    { text = "Demons can only be permanently killed in the Twisting Nether and Naaru can only be permanently killed in the realm of Light. Only exceptionally powerful entities can bypass this restriction." },
    { text = "Kobolds are possessive of their candles because they have a primal fear of the voidwraith called the Devouring Darkness." },
    { text = "Members of the Horde can learn Gnomish Engineering thanks to the gnome Oglethorpe Obnoticus. He was falsely accused for crimes he did not commit and exiled from Gnomeregan, so he teaches the Horde as an act of revenge." },
    { text = "Azeroth has two moons, the White Lady and the Blue Child. Every 430 years, they overlap each other in an event called the Embrace—because it appears as if the \"mother\" is holding her \"child\"." },
    { text = "It's sheer coincidence that the orcish Blackrock clan headquartered in Blackrock Mountain. The clan was named after blackrock ore in Draenor, long before the Horde's invasion of Azeroth." },
    { text = "There once existed a legendary sword called Andonisus, Reaper of Souls. It could only be wielded for up to five minutes during the fight against the demon Atiesh in Stratholme. It would kill its wielder in 20 seconds if not healed." },
    { text = "The leader of the Scarlet Crusade was a demon in disguise." },
    { text = "Despite being allies, the Knights of the Ebon Blade attacked Light's Hope Chapel in hopes of raising Tirion Fordring's corpse as a member of the Four Horsemen. They failed in their endeavor." },
    { text = "Standard Ironforge rations include haggis and beer. It's been a staple for the dwarven military for over a millenium." },
    { text = "The Alliance once set a trap for Thrall in the Stonetalon Mountains where they polymorphed themselves into sheep, ready to ambush. Thrall saw through the ruse, since sheep are not native to Kalimdor." },
    { text = "There is a long-held belief among night elves that those with golden eyes are destined for greatness. Prominent golden-eyed night elves include Queen Azshara and Illidan Stormrage." },
    { text = "The orcish tradition of Mak'gora involves a ritualistic duel to the death to settle disputes, usually for leadership." },
    { text = "Orcs are natively brown. After drinking the corrupted blood of the pit lord Mannoroth, most orc skin turned green." },
    { text = "The road between the Dark Portal and Hellfire Citadel is paved with the bones of thousands of murdered Draenei." },
    { text = "If you listen closely in the throne room at the entrance to the Undercity, you can hear the ghostly whispers of Arthas killing his father." },
    { text = "Tauren hooves have been used as a secret ingredient for candy." },
    { text = "Rogues used to blind opponents using an irritant made from Fadeleaf. Eventually, they stopped doing so, opting to use dirt or sand instead." },
    { text = "The Dark Riders of Deadwind Pass were once a band of travelling merchants who tried to sell fraudulent artifacts to Medivh. Now, they are cursed to forever seek real artifacts and return them to the Guardian." },
    { text = "Silver is heavy, but pretty, and used in jewelry and trinkets. Truesilver is lighter and stronger than steel, so it is more suited for armor and weapons." },
    { text = "The Kirin Tor Tavern Crawl was an event where mages set up portals between various bars and taverns of the world. Participants were encouraged to try something new at each destination." },
    { text = "Wolves in Elwynn Forest can be observed hunting and killing rabbits." },
    { text = "There have been seven Warchiefs of the Horde: Blackhand the Destroyer, Orgrim Doomhammer, Ner'zhul, Thrall, Garrosh Hellscream, Vol'jin, and Sylvanas Windrunner. Now, it is ruled by a council of leaders." },
    { text = "The Sunwell used to have a human manifestation named Anveena Teague." },
    { text = "There are at least six derivative dragonflights that are corrupted or experimental offshoots of the main five." },
}

IMAGO.LoreSnippets["HISTORICAL_FACT"] = {
    { text = "The feared C'thraxxi creature named Kith'ix was a general for the Old Gods thousands of years ago. He was defeated and buried in Zul'Aman, where his body remains to this day." },
    { text = "Dath'remar Sunstrider founded Quel'Thalas after the War of the Ancients. His statue can be found on Sunstrider Isle." },
    { text = "The Radiant Song was heard not only on Azeroth, but also on the faraway world of K'aresh, shortly before it was destroyed." },
    { text = "The Dead Scar was almost completely healed by the Sunwell. Nowadays few traces of Arthas' invasion remain visible in Silvermoon." },
    { text = "The Defias Brotherhood was originally founded after the Kingdom of Stormwind refused to pay the stonemasons for their work in the reconstruction of Stormwind." },
    { text = "The Sunwell is roughly 7,000 years old." },
    { text = "Stormwind City was founded roughly 1,200 years before the First War. By Midnight, the city is physically ancient, but most of its visible infrastructure is rebuilt from the past 30-40 years of in-universe history." },
    { text = "Halduron Brightwing is the first Ranger-General of Silvermoon who isn't a Windrunner in at least three generations." },
    { text = "The orc Broxigar used an enchanted wooden axe to slice through the leg of Sargeras. He is one of the few mortals known to have injured the Titan." },
    { text = "Tanaris was once a lush jungle until the Great Sundering shattered the world and disrupted the climate." },
    { text = "The first paladins were created during the Second War to counteract the dark magic of the Horde. It was a mishmash of priests given military training and knights ordered to study holy books, but the desperate measure worked." },
    { text = "75 years before the First War, the Kingdom of Stormwind was nearly destroyed by gnolls." },
    { text = "The thorny vines that make up Razorfen Kraul and Razorfen Downs are the remains of the demigod Agamaggan, the Razorboar. He fell in battle against the Burning Legion during the War of the Ancients." },
    { text = "Gnomes were absent during the Third War because Gnomeregan was besieged by troggs at the time." },
    { text = "Humans discovered the holy powers of the Light around 3,000 years ago during the Troll Wars. Mereldar was the first human priestess to invoke its healing power." },
    { text = "Around 250 years ago, Dark Iron Sorcerer-Thane Thaurissan attempted to summon Ragnaros the Firelord to destroy his enemies. The resulting devastation killed him and created Blackrock Mountain." },
    { text = "Two-headed ogres were created during the Second War, when Gul'dan converted ancient elven runestones into structures called an Altar of Storms." },
    { text = "During the Second War, the King Perenolde of Alterac lost hope and switched sides to ally with the Horde. The Alliance destroyed Alterac in retaliation for this betrayal." },
    { text = "The Lunar Festival celebrates the end of the War of the Ancients, where the races of Azeroth repelled the Burning Legion invasion ten thousand years ago." },
    { text = "During the Second War, the orc Nekros Skullcrusher captured Alexstrasza and forced her children to fight on behalf of the Horde." },
    { text = "Ancient Draenor was covered in a hivemind of plants and fungus called the Evergrowth. It was destroyed when ancient Arakkoa activated a superweapon that used solar energy to devastating effect." },
    { text = "Around 2,600 years ago, the first Guardian of Tirisfal was created. They were mages imbued with immense power and the responsibility to defend Azeroth from demon invasion." },
    { text = "After the First War, the event was declared so significant that the calendar was reset. Year 0 marked when the Horde invaded Azeroth for the first time." },
    { text = "There exists a \"one true timeline\", and the Bronze Dragonflight is dedicated to its preservation." },
}
